  function toolbar(ph){return `<div class="action-row"><div class="search-wrap"><span class="search-ico">⌕</span><input class="search-input" id="mainSearch" type="text" placeholder="${esc(ph||'Caută module, surse, rute...')}"></div><button class="btn-icon" id="filterBtn" type="button" title="Filtre">⌘</button><div class="btn-group"><button class="btn-icon on" id="gridBtn" type="button" title="Grid view">▦</button><button class="btn-icon" id="listBtn" type="button" title="List view">☰</button></div><button class="btn btn-primary" id="refreshStatus" type="button">Refresh</button></div><div class="sv35-filter-panel" id="filterPanel"><button class="badge" data-filter="all" type="button">All</button><button class="badge" data-filter="battery" type="button">Battery</button><button class="badge" data-filter="market" type="button">Market</button><button class="badge" data-filter="source" type="button">Sources</button></div>`;}
  function overview(){return `${toolbar('Search SERVIO...')}<div class="sv35-page-grid"><div class="sv35-stack">${card('Usage',`<div class="sv35-usage-row"><div class="left"><span class="sv35-ring"></span><b>D1 records</b></div><span id="usage-d1">—</span></div><div class="sv35-usage-row"><div class="left"><span class="sv35-ring"></span><b>ENTSO-E records</b></div><span id="usage-entsoe">—</span></div><div class="sv35-usage-row"><div class="left"><span class="sv35-ring"></span><b>OPCOM records</b></div><span id="usage-opcom">—</span></div><div class="sv35-usage-row"><div class="left"><span class="sv35-ring"></span><b>Today completeness</b></div><span id="usage-today">—</span></div><div class="sv35-usage-row"><div class="left"><span class="sv35-ring"></span><b>Tomorrow completeness</b></div><span id="usage-tomorrow">—</span></div>`)}${card('Recent activity',`<div class="sv36-empty"><b>Ready</b><p>Modulele principale sunt disponibile în shell nativ, cu date și calcule actualizabile din butonul Refresh.</p></div>`)}</div><div class="sv35-stack">${card('Projects',`<div class="sv35-project-top"><span class="sv35-logo-circle">S</span><div><p class="sv35-project-title">SERVIO</p><p class="sv35-project-url">servio.vlad-it-taran.workers.dev</p><span class="sv35-repo-chip">◉ mrshoby/servio</span><p class="sv35-project-sub">Energy market calculators, day-ahead planning, forecasting and grid map.</p></div></div>`)}${card('Modules',`<div class="sv35-list sv35-module-list">${nav.filter(n=>n[0]!=='overview').map(n=>`<a class="sv35-list-row" data-module-card data-searchable href="${n[3]}"><span class="sv35-icon">${n[1]}</span><div><strong>${n[2]}</strong><p>${n[2].includes('Battery')?'Inputuri, rezultate, grafice și export.':n[2].includes('Day')?'Tabel, grafic și optimizare.':'Instrument SERVIO nativ în shell.'}</p></div><span>›</span></a>`).join('')}</div>`)}</div></div>`;}
  function loadCurve(){return `${toolbar('Search Consum / Curba de sarcină...')}<form id="loadCurveForm" class="sv36-grid two"><section class="sv36-card span"><div class="sv36-card-head"><h2>2. Sursa datelor</h2><div class="sv35-segment"><button type="button" data-mode="hourly" class="active">Încarc fișierul orar</button><button type="button" data-mode="invoice">Am doar factura lunară</button></div></div><div class="sv36-card-body"><div id="hourlyBox" class="sv36-upload"><label class="sv36-field"><span>Fișier orar / curba de sarcină</span><input id="consumptionFile" type="file" accept=".pdf,.jpg,.png,.xlsx,.xls,.csv"/></label><p class="sv36-help">Format acceptat: PDF, JPG, PNG, XLSX, XLS, CSV. Datele citite sunt folosite pentru analiza consumului și simularea Battery Revenue.</p></div><div id="invoiceBox" class="sv36-grid three hidden"><label class="sv36-field"><span>Consum facturat</span><div class="sv36-input-row"><input name="invoiceKwh" type="number" value="50000"/><em>kWh</em></div></label><label class="sv36-field"><span>Număr zile facturate</span><input name="invoiceDays" type="number" value="30"/></label><label class="sv36-field"><span>Profil estimat</span><select name="invoiceProfile"><option>Industrial zi</option><option>Continuu 24/7</option><option>Birouri</option></select></label></div></div></section>${card('Tarife și producție locală',`<div class="sv36-grid three">${input('energyPrice','Preț energie',0.78,'lei/kWh')}${input('transportTariff','Tarif transport',0.04,'lei/kWh')}${input('distributionTariff','Tarif distribuție',0.18,'lei/kWh')}${input('greenCert','Certificate / taxe',0.05,'lei/kWh')}${input('pvKw','PV local',400,'kWp')}${input('exportPrice','Preț export',0.30,'lei/kWh')}</div>`)}${card('Cum obții fișierul orar / curba de sarcină?',`<ol class="sv36-steps"><li>Intră în portalul furnizorului/distribuitorului.</li><li>Descarcă intervalele orare sau 15 minute pe perioada analizată.</li><li>Încarcă fișierul aici, apoi verifică sumarul înainte de BESS.</li></ol>`)}${card('Rezultatele analizei',`<div class="sv36-kpi-grid"><div id="analysisResult">Încarcă fișierul sau folosește factura lunară.</div></div><div class="sv36-actions"><button class="sv35-btn primary" type="button" id="goBess">Deschide Battery Revenue Simulator</button><button class="sv35-btn" type="button" id="exportLoadSummary">Export summary</button></div>`,'')}</form>`;}
  function paramsFrom(form, defs=defaults){const o={...defs}; new FormData(form).forEach((v,k)=>{const n=Number(v); o[k]=Number.isFinite(n)&&String(v).trim()!==''?n:v;}); return o;}
  function batteryMath(p){const usable=p.capacityMWh*Math.max(0,(p.maxSocPct-p.minSocPct)/100); const inv=p.capacityMWh*1000*p.batteryCostEurKwh; const dailyCycles=Math.min(p.maxCyclesDay, p.lifecycleCycles/(p.projectYears*365)); const yearlyThroughput=usable*dailyCycles*365; const spreadRon=Math.max(0,p.minDischargePriceRonMwh-p.maxChargePriceRonMwh-p.degradationCostRonMwh); const annualRon=yearlyThroughput*spreadRon*(p.efficiencyPct/100)-p.fixedOmEurYear*p.eurRon; const annualEur=annualRon/p.eurRon; const roi=inv>0?annualEur/inv*100:0; const payback=annualEur>0?inv/annualEur:null; return {usable,inv,dailyCycles,yearlyThroughput,spreadRon,annualRon,annualEur,roi,payback};}
  function fieldsBattery(defs=defaults){return `${card('Battery Specifications',`<div class="sv36-grid six">${input('capacityMWh','Capacity',defs.capacityMWh,'MWh')}${input('maxChargePowerMW','Max charge power',defs.maxChargePowerMW,'MW')}${input('maxDischargePowerMW','Max discharge power',defs.maxDischargePowerMW,'MW')}${input('efficiencyPct','Round-trip efficiency',defs.efficiencyPct,'%')}${input('maxCyclesDay','Max cycles / day',defs.maxCyclesDay,'cycles')}${input('minSocPct','Min SOC',defs.minSocPct,'%')}${input('maxSocPct','Max SOC',defs.maxSocPct,'%')}</div>`)}${card('Investment & Lifecycle',`<div class="sv36-grid six">${input('batteryCostEurKwh','Battery cost',defs.batteryCostEurKwh,'€/kWh')}${input('eurRon','EUR/RON rate',defs.eurRon,'lei/€')}${input('lifecycleCycles','Lifecycle cycles',defs.lifecycleCycles,'cycles')}${input('fixedOmEurYear','Fixed O&M',defs.fixedOmEurYear,'€/year')}${input('discountPct','Discount rate',defs.discountPct,'%')}${input('projectYears','Project life',defs.projectYears,'years')}</div>`)}${card('Price Thresholds',`<div class="sv36-grid four">${input('degradationCostRonMwh','Degradation cost',defs.degradationCostRonMwh,'lei/MWh')}${input('maxChargePriceRonMwh','Max charge price',defs.maxChargePriceRonMwh,'lei/MWh')}${input('minDischargePriceRonMwh','Min discharge price',defs.minDischargePriceRonMwh,'lei/MWh')}${input('maxIdChargePriceRonMwh','Max ID charge price',defs.maxIdChargePriceRonMwh,'lei/MWh')}</div>`)}`;}
  function batteryPage(){return `${toolbar('Search Battery Revenue Simulator...')}<form id="batteryForm" class="sv36-native" data-module="battery">${fieldsBattery(defaults)}${card('Scenario presets',`<div class="sv35-segment"><button type="button" data-battery-preset="conservative">Conservative</button><button type="button" data-battery-preset="balanced" class="active">Balanced</button><button type="button" data-battery-preset="aggressive">Aggressive</button><button type="button" data-battery-preset="peak">Peak shaving</button></div>`)}${card('Results',`<div id="batteryKpis" class="sv36-kpi-grid"></div>`)}${card('Grafic',`<div id="batteryChart" class="sv36-chart"></div>`)}${card('Tabel rezultate',`<div class="sv35-table"><table><thead><tr><th>Scenario</th><th>Investment</th><th>Annual value</th><th>ROI</th><th>Payback</th></tr></thead><tbody id="batteryTable"></tbody></table></div><div class="sv36-actions"><button type="button" class="sv35-btn" id="exportBatteryCsv">Export CSV</button><button type="button" class="sv35-btn" id="exportBatteryJson">Export JSON</button></div>`)}</form>`;}
  function dispatchGrid(){let html='<div class="sv36-dispatch" id="dispatchGrid"><div class="sv36-dispatch-head"><span></span>'; for(let h=0;h<24;h++)html+=`<b>${String(h).padStart(2,'0')}</b>`; html+='</div>'; for(let q=0;q<4;q++){html+=`<div class="sv36-dispatch-row"><em>${q*15}</em>`; for(let h=0;h<24;h++){const interval=(h*4)+q+1; html+=`<button type="button" class="sv36-cell idle" data-hour="${h}" data-q="${q}" data-interval="${interval}" data-mode="idle">0</button>`;} html+='</div>'; } return html+'</div>';}
  function revenuePage(){return `${toolbar('Search Battery Revenue Simulator...')}<form id="revenueForm" class="sv36-native" data-module="revenue">${fieldsBattery(revenueDefaults)}${card('Custom Simulation Period',`<div class="sv36-grid four"><label class="sv36-check"><input type="checkbox" name="customPeriod" checked/> <span>Custom simulation period</span></label>${input('from','From','2023-10-01','', 'date')}${input('to','To','2026-03-31','', 'date')}<button type="button" class="sv35-btn" id="useFullDataset">Use full dataset</button></div><div class="sv36-note" id="revenueDatasetNote">Se încarcă datasetul oficial...</div>`)}${card('Dispatch Strategy',`<div class="sv36-grid"><div class="sv36-actions left"><span class="sv36-mini-label">Brush</span><button type="button" class="sv35-btn primary" data-brush="charge">Charge</button><button type="button" class="sv35-btn" data-brush="discharge">Discharge</button><button type="button" class="sv35-btn" data-brush="idle">Erase</button><span class="sv36-mini-label">Presets</span><button type="button" class="sv35-btn" data-dispatch-preset="night">Night→Peak</button><button type="button" class="sv35-btn" data-dispatch-preset="offpeak">Off-Peak→Peak</button><button type="button" class="sv35-btn" data-dispatch-preset="pv">PV Peak→Evening</button><button type="button" class="sv35-btn" data-dispatch-preset="clear">Clear</button></div>${dispatchGrid()}<div class="sv36-legend" id="dispatchLegend"><span><i class="charge"></i>Charge</span><span><i class="discharge"></i>Discharge</span><span><i></i>Idle</span></div></div>`)}${card('Revenue & ROI',`<div id="revenueKpis" class="sv36-kpi-grid"></div>`)}${card('Monthly Revenue',`<div id="revenueChart" class="sv36-chart tall"></div>`)}${card('Tabel lunar',`<div class="sv35-table"><table><thead><tr><th>Month</th><th>Revenue</th><th>Cumulative</th><th>Cycles</th><th>Charge</th><th>Discharge</th><th>ID charge</th></tr></thead><tbody id="revenueTable"></tbody></table></div><div class="sv36-actions"><button type="button" class="sv35-btn" id="exportRevenueCsv">Export CSV</button><button type="button" class="sv35-btn" id="exportRevenueJson">Export JSON</button></div>`)}</form>`;}
  function dayAheadPage(){return `${toolbar('Search Day-Ahead...')}<div class="sv36-native" data-module="day-ahead">${card('Day-Ahead / Piață energie',`<div class="sv36-grid four"><label class="sv36-field"><span>Delivery day</span><input id="daDate" type="date" value="${addDays(todayIso(),1)}"/></label>${select('resolution','Resolution',[['15','15 min'],['60','60 min']],'15')}<button type="button" class="sv35-btn primary" id="refreshDayAhead">Refresh data</button><button type="button" class="sv35-btn" id="exportDayAheadCsv">Export CSV</button></div>`)}${card('Status',`<div id="dayAheadKpis" class="sv36-kpi-grid"></div>`)}${card('Grafic prețuri',`<div id="dayAheadChart" class="sv36-chart tall"></div>`)}${card('Tabel complet',`<div class="sv35-table"><table><thead><tr><th>Interval</th><th>Ora</th><th>Price RON/MWh</th><th>Price EUR/MWh</th><th>Action</th></tr></thead><tbody id="dayAheadTable"></tbody></table></div>`)}</div>`;}
