  async function refreshStatus(){try{const r=await fetch('/api/servio/db/status-fast',{cache:'no-store'}); const d=await r.json(); store.status=d; setChip('#chipApi',true,'Online'); setChip('#chipD1',!!d.d1,'Date'); setChip('#chipLive',true,'Sync'); const sd=$('#topbar-status-dot'), st=$('#topbar-status-text'); if(sd){sd.className='status-dot live';} if(st){st.textContent='Live';} setText('#usage-d1',fmt(d.d1Sync?.totalRows||d.rawRecords||0)); setText('#usage-entsoe',fmt(d.d1Sync?.sourceModes?.['official-live']||0)); setText('#usage-opcom',fmt(d.d1Sync?.sourceModes?.['opcom-pzu-live']||0)); const today=d.dayAheadCompact?.today, tomorrow=d.dayAheadCompact?.tomorrow; setText('#usage-today',today?`${today.count||0}/${today.expected||96}`:'—'); setText('#usage-tomorrow',tomorrow?`${tomorrow.count||0}/${tomorrow.expected||96}`:'—');}catch(e){setChip('#chipApi',false,'Online'); const sd=$('#topbar-status-dot'), st=$('#topbar-status-text'); if(sd){sd.className='status-dot error';} if(st){st.textContent='Offline';}}}
